export type Level = 'N5' | 'N4-light' | 'N4-core' | 'N3'
export type Theme = 'station' | 'rain' | 'cafe' | 'books' | 'animals' | 'night' | 'design' | 'path' | 'school' | 'shopping' | 'food' | 'nature'

export interface Scene {
  id: string; level: Level; theme: Theme
  title: string; titleEn?: string
  text: string; textEn?: string
  jp_text: string; jp_translation: string
  words: [string, string, string][]
  phrase: [string, string, string]
  question: { text: string; options: string[]; correct: number; explanation?: string }
  reflection: string
  michi_state: 'night_watcher' | 'traveler' | 'reader' | 'coffee' | 'explorer'
  track?: 'journey' | 'live' | 'study' | 'design' | 'expression'
  grammar_focus?: string
  skill_focus?: 'reading' | 'listening' | 'speaking' | 'writing' | 'mixed'
  academic?: boolean
  design?: boolean
}

export function shuffleOptions(scene: Scene): Scene {
  const opts = [...scene.question.options]
  const correctText = opts[scene.question.correct]
  for (let i = opts.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [opts[i], opts[j]] = [opts[j], opts[i]]
  }
  return { ...scene, question: { ...scene.question, options: opts, correct: opts.indexOf(correctText) } }
}

