const scenes: Scene[] = [...n5, ...n5x, ...n4l, ...n4lx, ...n4c, ...n4cx, ...n3, ...n3x]
export default scenes

export function getSceneForDay(userId: number, level: Level): Scene {
  const filtered = scenes.filter(s => s.level === level)
  const pool = filtered.length > 0 ? filtered : scenes
  const dayOfYear = Math.floor(Date.now() / (1000 * 60 * 60 * 24))
  const idx = (dayOfYear + userId) % pool.length
  return shuffleOptions(pool[idx])
}

export function getNextLevel(current: Level): Level {
  const order: Level[] = ['N5', 'N4-light', 'N4-core', 'N3']
  return order[Math.min(order.indexOf(current) + 1, order.length - 1)]
}

export function getPrevLevel(current: Level): Level {
  const order: Level[] = ['N5', 'N4-light', 'N4-core', 'N3']
  return order[Math.max(order.indexOf(current) - 1, 0)]
}
